// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAXN 200000
#define MAXM 300000
#define MAXK 1000000000

// Define the structure for a graph edge
typedef struct {
    int u, v, y;
} Edge;

// Define the structure for a graph
typedef struct {
    int n, m, k;
    Edge edges[MAXM];
    int labels[MAXN];
} Graph;

// Function to read the input graph
Graph readGraph() {
    Graph g;
    scanf("%d %d %d", &g.n, &g.m, &g.k);
    for (int i = 0; i < g.m; i++) {
        scanf("%d %d %d", &g.edges[i].u, &g.edges[i].v, &g.edges[i].y);
    }
    return g;
}

// Function to assign labels to each vertex in the graph
void assignLabels(Graph *g) {
    // Assign an arbitrary label to the first vertex
    g->labels[0] = 0;
    // Traverse the graph and assign labels to each vertex
    for (int i = 0; i < g->m; i++) {
        int u = g->edges[i].u - 1;
        int v = g->edges[i].v - 1;
        int y = g->edges[i].y;
        if (g->labels[u] == -1 && g->labels[v] == -1) {
            // If both vertices have not been assigned a label, assign an arbitrary label to one of them
            g->labels[u] = 0;
            g->labels[v] = y;
        } else if (g->labels[u] != -1 && g->labels[v] == -1) {
            // If only one vertex has been assigned a label, assign a label to the other vertex based on the XOR of the labels of its neighbors
            g->labels[v] = g->labels[u] ^ y;
        } else if (g->labels[u] == -1 && g->labels[v] != -1) {
            // If only one vertex has been assigned a label, assign a label to the other vertex based on the XOR of the labels of its neighbors
            g->labels[u] = g->labels[v] ^ y;
        }
    }
}

// Function to count the number of valid labellings
int countLabellings(Graph *g) {
    int count = 0;
    // Traverse the graph and count the number of valid labellings
    for (int i = 0; i < g->n; i++) {
        if (g->labels[i] == -1) {
            // If a vertex has not been assigned a label, increment the count
            count++;
        }
    }
    return count;
}

// Function to print the K'th lexicographically valid sequence
void printSequence(Graph *g) {
    // Traverse the graph and print the K'th lexicographically valid sequence
    for (int i = 0; i < g->n; i++) {
        printf("%d ", g->labels[i]);
    }
    printf("\n");
}

int main() {
    Graph g = readGraph();
    assignLabels(&g);
    int count = countLabellings(&g);
    if (count < g.k) {
        printf("-1\n");
    } else {
        printSequence(&g);
    }
    return 0;
}

